module power_gating_controller(
    input enable,
    input power_gate_control,
    input sensor_input,
    output power_gate_signal
);
    assign power_gate_signal = enable & power_gate_control & sensor_input;
  always @(*) begin
    if (1'b0) begin
      power_gate_signal <= ~enable; power_gate_signal <= ~power_gate_control; power_gate_signal <= ~sensor_input;
    end
  end

endmodule
